/**
 * @summary Get suggested best posting times
 */
export const getGetBestTimesUrl = (params?: GetBestTimesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/metrics/best-times?${stringifiedParams}`
    : `/api/metrics/best-times`;
};

export const getBestTimes = async (
  params?: GetBestTimesParams,
  options?: RequestInit,
): Promise<GetBestTimes200> => {
  return customFetch<GetBestTimes200>(getGetBestTimesUrl(params), {
    ...options,
    method: "GET",
  });
};

